import "./App.css"
import React, { useState } from "react";
<img src={product.image} alt={product.name} width="200" />
function App() {
  const [cart, setCart] = useState([]);

  const products = [
    { id: 1,
       name: "20*5",
       grade:"N-35",
       Image:"https://r.search.yahoo.com/_ylt=AwrKGERVdSpqtt0gJZjGHAx.;_ylu=c2VjA2ZwLWF0dHJpYgRzbGsDcnVybA--/RV=2/RE=1781196245/RO=11/RU=https%3a%2f%2fwww.tinytronics.nl%2fnl%2fgereedschap-en-montage%2finstallatie-en-montagemateriaal%2fmagneten%2fxmp-neodymium-magneet-20x5-n35/RK=2/RS=ASw5zZKRKM5cyY1uB9MCMSjHYP4-",
        price: "500" },
    { id: 2, name: "Phone", price: 20000 },
    { id: 3, name: "Headphone", price: 2000 },
  ];

  const addToCart = (product) => {
    setCart([...cart, product]);
  };

  return (
    <div style={{ padding: "20px" }}>
      <h1>Simple E-Commerce Website</h1>

      <h2>Cart Items: {cart.length}</h2>

      {products.map((product) => (
        <div key={product.id}>
          <h3>{product.name}</h3>
          <p>₹{product.price}</p>
          <button onClick={() => addToCart(product)}>
            Add to Cart
          </button>
          <hr />
        </div>
      ))}
    </div>
  );
}

export default App;
